import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.D5wUhsuj.js";const k=JSON.parse('{"title":"Deploy a Laravel App","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/deploy-laravel.md","filePath":"tutorials/deploy-laravel.md"}'),t={name:"tutorials/deploy-laravel.md"};function p(l,s,h,r,o,d){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="deploy-a-laravel-app" tabindex="-1">Deploy a Laravel App <a class="header-anchor" href="#deploy-a-laravel-app" aria-label="Permalink to &quot;Deploy a Laravel App&quot;">​</a></h1><p>A walkthrough for getting a Laravel application running on AidiPanel, from a fresh site to a live app with SSL. This assumes your app already exists in a Git repository — either your own project or something you&#39;re deploying from a template.</p><p><strong>Before you start:</strong></p><ul><li>AidiPanel is installed and you can log into the panel</li><li>Your Laravel app is in a Git repository you can clone from the server (public repo, or SSH/token access set up for a private one)</li><li>A domain pointed at your server</li></ul><h2 id="_1-create-the-site" tabindex="-1">1. Create the site <a class="header-anchor" href="#_1-create-the-site" aria-label="Permalink to &quot;1. Create the site&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> site:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> laravel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Using <code>--type laravel</code> (rather than plain <code>php</code>) matters here: it tells AidiPanel to point the Nginx vhost&#39;s document root at <code>public/</code> instead of the site root, which is exactly where Laravel expects incoming requests to land.</p><p>This creates the dedicated Linux user <code>myapp</code>, an isolated PHP-FPM pool running as that user, and the web root at <code>/home/myapp/htdocs/myapp.com</code>.</p><h2 id="_2-clone-and-install" tabindex="-1">2. Clone and install <a class="header-anchor" href="#_2-clone-and-install" aria-label="Permalink to &quot;2. Clone and install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  cd /home/myapp/htdocs/myapp.com</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  git clone https://github.com/your/repo.git .</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  composer install --no-dev --optimize-autoloader</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>The trailing <code>.</code> on <code>git clone</code> clones directly into the current (already-created) directory instead of making a new subfolder. <code>--no-dev</code> skips dev-only dependencies (test frameworks, debug tools) you don&#39;t want on production; <code>--optimize-autoloader</code> speeds up class loading for a real deployment.</p><div class="tip custom-block"><p class="custom-block-title">No Composer on the server yet?</p><p>AidiPanel&#39;s default install doesn&#39;t assume every site needs Composer. If <code>composer</code> isn&#39;t found, install it directly: <code>curl -sS https://getcomposer.org/installer | php -- --install-dir=/usr/local/bin --filename=composer</code>.</p></div><h2 id="_3-configure-the-environment" tabindex="-1">3. Configure the environment <a class="header-anchor" href="#_3-configure-the-environment" aria-label="Permalink to &quot;3. Configure the environment&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  cd /home/myapp/htdocs/myapp.com</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  cp .env.example .env</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  php artisan key:generate</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Now edit <code>.env</code> and fill in your database credentials (create the database first if you haven&#39;t — see <a href="/docs/guide/sites#installing-wordpress">Site Management → Installing WordPress, step 3</a> for the equivalent <code>db:add</code> pattern, it&#39;s identical for Laravel):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp_db</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp_db_user</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This prints a generated password once — save it, then put it straight into <code>.env</code>:</p><div class="language-dotenv vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dotenv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_CONNECTION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_HOST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">3306</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_DATABASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">myapp_db</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_USERNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">myapp_db_user</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">DB_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;the generated password&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="_4-run-migrations" tabindex="-1">4. Run migrations <a class="header-anchor" href="#_4-run-migrations" aria-label="Permalink to &quot;4. Run migrations&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;cd /home/myapp/htdocs/myapp.com &amp;&amp; php artisan migrate --force&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Add <code>--seed</code> if your app ships seeders you want run on first deploy. If this fails with a connection error, double-check the four DB values above — same troubleshooting path as WordPress: <a href="/docs/troubleshooting/permissions-database#error-establishing-a-database-connection">Permissions &amp; Database</a>.</p><h2 id="_5-fix-ownership-and-storage-permissions" tabindex="-1">5. Fix ownership and storage permissions <a class="header-anchor" href="#_5-fix-ownership-and-storage-permissions" aria-label="Permalink to &quot;5. Fix ownership and storage permissions&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp:myapp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/myapp/htdocs/myapp.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u+rwX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/myapp/htdocs/myapp.com/storage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u+rwX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/myapp/htdocs/myapp.com/bootstrap/cache</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Laravel writes logs, compiled views, and cache files into <code>storage/</code> and <code>bootstrap/cache/</code> constantly — if PHP (running as <code>myapp</code>) can&#39;t write there, you&#39;ll get a <code>500</code> with a permissions error in <code>storage/logs/laravel.log</code> the moment the app tries to do anything.</p><div class="warning custom-block"><p class="custom-block-title">Don&#39;t chmod 777</p><p><code>775</code> is enough since PHP-FPM already runs as the owning user (<code>myapp</code>) — there&#39;s no other process on the box that needs write access to these folders. <code>777</code> opens them to every user on the system for no benefit.</p></div><h2 id="_6-set-production-mode" tabindex="-1">6. Set production mode <a class="header-anchor" href="#_6-set-production-mode" aria-label="Permalink to &quot;6. Set production mode&quot;">​</a></h2><p>In <code>.env</code>:</p><div class="language-dotenv vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dotenv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">APP_ENV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">production</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">APP_DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="danger custom-block"><p class="custom-block-title">Never leave APP_DEBUG=true in production</p><p>With debug mode on, an unhandled exception dumps a full stack trace — including your <code>.env</code> values — straight to the browser. Turn it off before you point real traffic at the site.</p></div><p>Then cache the config and routes for a speed boost:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  cd /home/myapp/htdocs/myapp.com</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  php artisan config:cache</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  php artisan route:cache</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  php artisan view:cache</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">Remember to clear these after every deploy</p><p>If you update <code>.env</code> or your routes later and the app doesn&#39;t seem to notice, you likely have a stale cache from this step. Re-run <code>php artisan config:clear &amp;&amp; php artisan route:clear</code> (or re-run the <code>:cache</code> versions after your change) — this is one of the most common &quot;why isn&#39;t my change showing up&quot; moments in Laravel specifically.</p></div><h2 id="_7-install-ssl" tabindex="-1">7. Install SSL <a class="header-anchor" href="#_7-install-ssl" aria-label="Permalink to &quot;7. Install SSL&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # confirm DNS has propagated first</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@myapp.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="_8-the-scheduler-if-your-app-uses-one" tabindex="-1">8. The scheduler (if your app uses one) <a class="header-anchor" href="#_8-the-scheduler-if-your-app-uses-one" aria-label="Permalink to &quot;8. The scheduler (if your app uses one)&quot;">​</a></h2><p>If your app has scheduled tasks, Laravel needs one cron entry. Add it through AidiPanel so it is validated and installed in the site&#39;s own crontab:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%s\\n&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;cd /home/myapp/htdocs/myapp.com &amp;&amp; php artisan schedule:run &gt;&gt; /dev/null 2&gt;&amp;1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myapp.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --schedule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;* * * * *&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Running it as <code>myapp</code> (rather than root) keeps it consistent with the same isolation model as everything else — the scheduler can only touch what that site&#39;s user can touch.</p><h2 id="done" tabindex="-1">Done <a class="header-anchor" href="#done" aria-label="Permalink to &quot;Done&quot;">​</a></h2><p>Your Laravel app is live, migrated, and served over HTTPS with an isolated PHP-FPM pool. A few things worth knowing as you keep working on it:</p><ul><li><strong>Redeploying:</strong> <code>git pull</code>, <code>composer install --no-dev</code>, re-run any new migrations, then <code>php artisan config:cache route:cache view:cache</code> again. Consider scripting this as a small <code>deploy.sh</code> in the repo.</li><li><strong>Switching PHP version:</strong> see <a href="/docs/guide/php">PHP Management</a> if your app needs a specific version.</li><li><strong>FastCGI Cache:</strong> Laravel apps are usually far more dynamic/session-heavy than a WordPress blog, so full-page caching is rarely a fit — the <a href="/docs/guide/fastcgi-cache">FastCGI Cache</a> exclusion rules already skip logged-in and cookie-bearing requests, but you may want to leave page cache off entirely for an authenticated app and rely on Laravel&#39;s own caching (<code>config:cache</code>, query caching, Redis) instead.</li></ul>`,41)])])}const u=a(t,[["render",p]]);export{k as __pageData,u as default};
